-- ============================================================
-- StudyCircle seed data — single procedural transaction
-- Order: profiles -> groups -> posts -> comments -> search_corpus -> profile_groups
-- Prerequisite: schema (app_db.sql) already applied to the target DB.
-- ============================================================
PRAGMA foreign_keys = ON;   -- enforce referential integrity on load (set OUTSIDE the txn)

BEGIN TRANSACTION;

-- ---- [1/6] profiles: Seed users (110 profiles, classes 6-12) ----

-- ---- [2/6] groups: Study & problem groups (20) ----

-- ---- [3/6] posts: Feed posts (234 incl. reposts) — author_profile_id, group_id, repost_of FKs ----

-- ---- [4/6] comments: Threaded comments (551) + reconcile posts.comment_count ----
UPDATE "posts" SET "comment_count" = (SELECT COUNT(*) FROM "comments" WHERE "comments"."post_id" = "posts"."id");

-- ---- [5/6] search_corpus: Stratified search index (66 rows) ----

-- ---- [6/6] profile_groups: Group memberships (480) — post-coherent + lurkers ----

COMMIT;
